import React, { useEffect, useState } from "react";
import axios from "axios";

const RoleRequests = () => {
  const [requests, setRequests] = useState([]);

  useEffect(() => {
    const fetchRequests = async () => {
      try {
        const token = localStorage.getItem("token");
        const response = await axios.get(
          "http://localhost:3000/api/users/pending-role-requests",
          { headers: { Authorization: `Bearer ${token}` } }
        );
        setRequests(response.data);
      } catch (error) {
        console.error("Error fetching role requests:", error);
      }
    };

    fetchRequests();
  }, []);

  const handleApprove = async (id) => {
    try {
      const token = localStorage.getItem("token");
      await axios.put(
        `http://localhost:3000/api/users/approve-role/${id}`,
        {},
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert("Role approved successfully!");
      setRequests(requests.filter((req) => req.id !== id));
    } catch (error) {
      console.error("Error approving role:", error);
    }
  };

  const handleReject = async (id) => {
    try {
      const token = localStorage.getItem("token");
      await axios.delete(
        `http://localhost:3000/api/users/reject-role/${id}`,
        { headers: { Authorization: `Bearer ${token}` } }
      );

      alert("Role rejected successfully!");
      setRequests(requests.filter((req) => req.id !== id));
    } catch (error) {
      console.error("Error rejecting role:", error);
    }
  };

  return (
    <div>
      <h2>Pending Role Requests</h2>
      {requests.length === 0 ? (
        <p>No pending role requests.</p>
      ) : (
        <table>
          <thead>
            <tr>
              <th>Username</th>
              <th>Email</th>
              <th>Requested Role</th>
              <th>Actions</th>
            </tr>
          </thead>
          <tbody>
            {requests.map((req) => (
              <tr key={req.id}>
                <td>{req.username}</td>
                <td>{req.email}</td>
                <td>{req.requested_role}</td>
                <td>
                  <button onClick={() => handleApprove(req.id)}>Approve</button>
                  <button onClick={() => handleReject(req.id)}>Reject</button>
                </td>
              </tr>
            ))}
          </tbody>
        </table>
      )}
    </div>
  );
};

export default RoleRequests;
